   412→async function loadDisputes() {
   413→    disputesList.innerHTML = `<div class="skeleton" style="height:60px"></div>`;
   414→    try {
   415→        const claims = await api.listDisputedClaims();
   416→        if (claims.length === 0) {
   417→            disputesList.innerHTML = `<div class="empty-state">No pending disputes.</div>`;
   418→            return;
   419→        }
   420→        disputesList.innerHTML = claims.map(c => renderDisputeCard(c)).join("");
