   427→function renderDisputeCard(claim) {
   428→    const d = claim.dispute;
   429→    return `
   430→        <div class="card" style="margin-bottom:12px" id="dispute-card-${claim.id}">
   431→            <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:10px;flex-wrap:wrap;gap:8px">
   432→                <div>
   433→                    <span class="id-mono">${claim.id}</span>
   434→                    <span style="margin-left:10px;font-weight:600">${claim.member.name}</span>
   435→                </div>
   436→                <div style="color:var(--text-muted);font-size:13px">Date of service: <strong>${claim.date_of_service}</strong></div>
   437→            </div>
   438→            <div style="margin-bottom:10px">
   439→                <div style="font-size:12px;font-weight:600;color:var(--text-muted);margin-bottom:4px">DISPUTE REASON</div>
   440→                <div>${d.reason}</div>
   441→            </div>
   442→            <div style="font-size:12px;color:var(--text-muted);margin-bottom:12px">
   443→                Submitted: ${new Date(d.submitted_at).toLocaleString()}
   444→            </div>
   445→            <div class="form-group">
   446→                <label for="reviewer-note-${claim.id}">Reviewer Note (optional)</label>
   447→                <textarea id="reviewer-note-${claim.id}" class="form-control" rows="3"
   448→                    placeholder="Notes from the reviewer…" style="resize:vertical"></textarea>
   449→            </div>
   450→            <div id="readjudicate-error-${claim.id}"></div>
   451→            <div class="form-actions">
   452→                <button id="readjudicate-btn-${claim.id}" class="btn btn-primary"
   453→                    data-claim="${claim.id}">Trigger Re-adjudication</button>
   454→            </div>
   455→        </div>`;
   456→}
   457→
   458→function wireDisputeCard(claim) {
   459→    const btn   = document.getElementById(`readjudicate-btn-${claim.id}`);
   460→    const errEl = document.getElementById(`readjudicate-error-${claim.id}`);
   461→    if (!btn) return;
   462→    btn.addEventListener("click", async () => {
   463→        const note = document.getElementById(`reviewer-note-${claim.id}`).value.trim() || null;
   464→        btn.disabled = true;
   465→        btn.textContent = "Processing…";
   466→        try {
   467→            await api.adjudicate(claim.id, note);
   468→            await loadDisputes();
   469→        } catch (err) {
   470→            showError(errEl, err.message);
   471→            btn.disabled = false;
   472→            btn.textContent = "Trigger Re-adjudication";
   473→        }
   474→    });
   475→}
